  if (existing) {
    existing.qty += qty;
  } else {
    cart.items.push({ id, qty, price });
  }
}
function setQty(cart, id, qty) {
  const existing = cart.items.find(it => it.id === id);
  if (!existing) return;
  if (qty <= 0) {
    cart.items = cart.items.filter(it => it.id !== id);
  } else {
    existing.qty = qty;
  }
}

